    def processArray(self, arr: list[int]) -> list[int]:
        return arr

    def main(self):
        arr = [1, 2, 3]
        print(self.processArray(arr))  # Output: [1, 2, 3]

    def read_input(self):
        line = input()
        return eval(line)

    def write_output(self, arr: list[int]) -> None:
        print(arr)

    def execute(self):
        arr = self.read_input()
        self.write_output(self.processArray(arr))

if __name__ == '__main__':
    solution = Solution()
    solution.main()
